#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long s,e;
} a[100005];
bool fun(node x,node y)
{
    return x.s<y.s;
}
long long ans=0;
int n;
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++) cin>>a[i].s>>a[i].e;
    sort(a+1,a+1+n,fun);
    long long st=-1,en=-1;
    for(int i=1;i<=n;i++)
    {
        if(st==-1) st=a[i].s,en=a[i].e;
        else
        {
            if(a[i].s<=en) en=max(en,a[i].e);
            else
            {
                ans+=(en-st+1);
                st=a[i].s,en=a[i].e;
            }
        }
    }
    if(st!=-1) ans+=(en-st+1);
    cout<<ans;
    return 0;
}
